import * as React from 'react';

export function HeroLogo(props: React.SVGProps<SVGSVGElement>) {
  return (
    <svg
      width={149}
      height={143}
      viewBox="0 0 149 143"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      xmlnsXlink="http://www.w3.org/1999/xlink"
      {...props}
    >
      <g clipPath="url(#clip0_10812_10516)">
        <rect x={-47} y={-58} width={248} height={259} fill="url(#pattern0_10812_10516)" />
      </g>

      <defs>
        <pattern
          id="pattern0_10812_10516"
          patternContentUnits="objectBoundingBox"
          width={1}
          height={1}
        >
          <use
            xlinkHref="#image0_10812_10516"
            transform="matrix(0.000254969 0 0 0.000244141 -0.0221774 0)"
          />
        </pattern>

        <clipPath id="clip0_10812_10516">
          <rect width={149} height={143} fill="white" />
        </clipPath>

        <image
          id="image0_10812_10516"
          width={4096}
          height={4096}
          preserveAspectRatio="none"
          xlinkHref="data:image/png;base64,"
        />
      </defs>
    </svg>
  );
}


